patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index 439a86d951a8..d9e8c2b9e5fd 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -1706,6 +1706,7 @@ static Value *foldOperationIntoSelectOperand(Instruction &I, SelectInst *SI,
   return Clone;
 }

+
 Instruction *InstCombinerImpl::FoldOpIntoSelect(Instruction &Op, SelectInst *SI,
                                                 bool FoldWithMultiUse) {
   // Don't modify shared select instructions unless set FoldWithMultiUse
@@ -1729,8 +1730,68 @@ Instruction *InstCombinerImpl::FoldOpIntoSelect(Instruction &Op, SelectInst *SI,
   if (auto *CI = dyn_cast<FCmpInst>(SI->getCondition())) {
     if (CI->hasOneUse()) {
       Value *Op0 = CI->getOperand(0), *Op1 = CI->getOperand(1);
-      if ((TV == Op0 && FV == Op1) || (FV == Op0 && TV == Op1))
-        return nullptr;
+      if ((TV == Op0 && FV == Op1) || (FV == Op0 && TV == Op1)) {
+        // Only skip if we're trying to fold the condition itself
+        if (&Op == CI)
+          return nullptr;
+      }
+    }
+  }
+
+  // Special case: fcmp ord X, 0.0 ? X : 0.0  followed by fcmp oeq with constant
+  // This pattern appears when clamping NaN to zero before comparison.
+  if (auto *FCI = dyn_cast<FCmpInst>(&Op)) {
+    if (FCI->getPredicate() == FCmpInst::FCMP_OEQ ||
+        FCI->getPredicate() == FCmpInst::FCMP_ONE ||
+        FCI->getPredicate() == FCmpInst::FCMP_OGT ||
+        FCI->getPredicate() == FCmpInst::FCMP_OGE ||
+        FCI->getPredicate() == FCmpInst::FCMP_OLT ||
+        FCI->getPredicate() == FCmpInst::FCMP_OLE) {
+      // Check if we're comparing the select result with a constant
+      Value *CmpLHS = FCI->getOperand(0);
+      Value *CmpRHS = FCI->getOperand(1);
+      ConstantFP *CFP = dyn_cast<ConstantFP>(CmpLHS);
+      Value *CmpVal = CmpRHS;
+      if (!CFP) {
+        CFP = dyn_cast<ConstantFP>(CmpRHS);
+        CmpVal = CmpLHS;
+      }
+      
+      if (CFP && CmpVal == SI) {
+        // Check if select condition is fcmp ord X, 0.0
+        if (auto *CondCmp = dyn_cast<FCmpInst>(SI->getCondition())) {
+          if (CondCmp->getPredicate() == FCmpInst::FCMP_ORD) {
+            Value *CondOp0 = CondCmp->getOperand(0);
+            Value *CondOp1 = CondCmp->getOperand(1);
+            ConstantFP *Zero = dyn_cast<ConstantFP>(CondOp1);
+            if (!Zero || !Zero->isZero())
+              Zero = dyn_cast<ConstantFP>(CondOp0);
+            
+            if (Zero && Zero->isZero() && 
+                ((CondOp0 == TV && CondOp1 == FV) || 
+                 (CondOp1 == TV && CondOp0 == FV))) {
+              // Pattern matched: fcmp ord X, 0.0 ? X : 0.0
+              // For ordered comparisons with constant C:
+              //   fcmp oeq (select ord X, 0.0, X, 0.0), C  -> fcmp oeq X, C
+              // This is safe because:
+              // - If X is ordered: select returns X, comparison works as usual
+              // - If X is NaN: select returns 0.0, and 0.0 != C for any C != 0.0
+              //   For C != 0.0, the transformation is valid.
+              //   For C == 0.0, we need to be careful with OEQ vs ONE.
+              if (!CFP->isZero() || FCI->getPredicate() != FCmpInst::FCMP_OEQ) {
+                Value *X = (TV == CondOp0) ? TV : FV;
+                // Create new comparison with same operand order as original
+                if (CmpLHS == SI)
+                  return FCmpInst::Create(Instruction::FCmp, FCI->getPredicate(),
+                                          X, CFP, "", SI);
+                else
+                  return FCmpInst::Create(Instruction::FCmp, FCI->getPredicate(),
+                                          CFP, X, "", SI);
+              }
+            }
+          }
+        }
+      }
     }
   }

@@ -1749,6 +1810,7 @@ Instruction *InstCombinerImpl::FoldOpIntoSelect(Instruction &Op, SelectInst *SI,
   return SelectInst::Create(SI->getCondition(), NewTV, NewFV, "", nullptr, SI);
 }

+
 static Value *simplifyInstructionWithPHI(Instruction &I, PHINode *PN,
                                          Value *InValue, BasicBlock *InBB,
                                          const DataLayout &DL,
